# Data_Analyst_Collaborator
# This system is designed to facilitate collaborative data analysis among multiple users or agents.
# It provides tools for data profiling, merging, and correlation analysis, and supports real-time collaboration.

import pandas as pd
from flask import Flask, request, jsonify
from flask_socketio import SocketIO, emit

app = Flask(__name__)
socketio = SocketIO(app)

# In-memory storage for datasets and analysis results
datasets = {}
analysis_results = {}

@app.route('/upload', methods=['POST'])
def upload_dataset():
    file = request.files['file']
    df = pd.read_csv(file)
    dataset_id = file.filename
    datasets[dataset_id] = df
    return jsonify({"message": f"Dataset {dataset_id} uploaded successfully"}), 200

@app.route('/profile/<dataset_id>', methods=['GET'])
def profile_dataset(dataset_id):
    if dataset_id not in datasets:
        return jsonify({"error": "Dataset not found"}), 404
    profile = datasets[dataset_id].describe()
    analysis_results[dataset_id] = {'profile': profile.to_dict()}
    return jsonify(profile.to_dict()), 200

@app.route('/merge', methods=['POST'])
def merge_datasets():
    data = request.json
    dataset_ids = data.get('datasets', [])
    if not dataset_ids or len(dataset_ids) < 2:
        return jsonify({"error": "Please provide at least two datasets to merge"}), 400
    try:
        merged_df = pd.concat([datasets[id] for id in dataset_ids])
        merged_id = '_'.join(dataset_ids)
        datasets[merged_id] = merged_df
        return jsonify({"message": f"Datasets merged successfully. New dataset ID: {merged_id}"}), 200
    except Exception as e:
        return jsonify({"error": str(e)}), 500

@app.route('/correlate/<dataset_id>', methods=['GET'])
def correlate_dataset(dataset_id):
    if dataset_id not in datasets:
        return jsonify({"error": "Dataset not found"}), 404
    correlation = datasets[dataset_id].corr()
    analysis_results[dataset_id]['correlation'] = correlation.to_dict()
    return jsonify(correlation.to_dict()), 200

@socketio.on('connect')
def handle_connect():
    emit('status', {'data': 'Connected to the Data_Analyst_Collaborator'})

@socketio.on('disconnect')
def handle_disconnect():
    print('Client disconnected')

if __name__ == '__main__':
    socketio.run(app, debug=True)
```

